    floor = cost + min_profit
    if offer >= floor:
        return {'decision': 'accept', 'price': offer}
    elif offer >= floor - 1.0:
        return {'decision': 'counter', 'price': floor, 'message': 'Best we can do'}
    else:
        return {'decision': 'decline', 'price': floor, 'message': f'Lowest is ${floor:.2f}'}
